import{_ as a,o as s,c as t,a2 as n}from"./chunks/framework.BYlK8ftn.js";const m=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md","lastUpdated":1782034459000}'),o={name:"guide/architecture.md"};function r(d,e,c,i,l,p){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="folder-structure" tabindex="-1">Folder structure <a class="header-anchor" href="#folder-structure" aria-label="Permalink to &quot;Folder structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>korovany/</span></span>
<span class="line"><span>├── .github/workflows/     # CI/CD: deploy.yml (Cloudflare Pages), docs.yml (GitHub Pages)</span></span>
<span class="line"><span>├── assets/                # source binary assets, tracked via Git LFS (models, textures, audio)</span></span>
<span class="line"><span>├── docs/                  # this VitePress documentation site → GitHub Pages</span></span>
<span class="line"><span>│   ├── .vitepress/        # docs site config</span></span>
<span class="line"><span>│   ├── guide/             # getting-started, project rules, architecture</span></span>
<span class="line"><span>│   └── operations/        # deployment &amp; credentials runbooks</span></span>
<span class="line"><span>├── public/                # static files served as-is at the web root</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── app/               # app shell &amp; top-level composition (App.tsx, full-page stage)</span></span>
<span class="line"><span>│   ├── components/        # reusable React UI components</span></span>
<span class="line"><span>│   ├── engine/            # Babylon Engine/Scene lifecycle (createGameEngine, resize, dispose)</span></span>
<span class="line"><span>│   ├── scenes/            # Babylon.js scenes + GameCanvas.tsx (thin React wrapper)</span></span>
<span class="line"><span>│   ├── game/              # engine-agnostic game logic (systems, entities, rules)</span></span>
<span class="line"><span>│   ├── store/             # Redux Toolkit store + slices, typed hooks</span></span>
<span class="line"><span>│   ├── hooks/             # shared React hooks</span></span>
<span class="line"><span>│   ├── assets/            # assets imported &amp; bundled by Vite</span></span>
<span class="line"><span>│   ├── styles/            # global styles</span></span>
<span class="line"><span>│   ├── types/             # shared TypeScript types</span></span>
<span class="line"><span>│   └── test/              # test setup (setup.ts)</span></span>
<span class="line"><span>├── AGENTS.md / CLAUDE.md  # rules for automated contributors</span></span>
<span class="line"><span>└── index.html             # Vite entry</span></span></code></pre></div><h2 id="where-new-code-goes" tabindex="-1">Where new code goes <a class="header-anchor" href="#where-new-code-goes" aria-label="Permalink to &quot;Where new code goes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>You are adding…</th><th>Put it in…</th></tr></thead><tbody><tr><td>A Babylon scene/world</td><td><code>src/scenes/</code></td></tr><tr><td>Engine/render-loop lifecycle</td><td><code>src/engine/</code></td></tr><tr><td>Reusable UI (buttons, HUD)</td><td><code>src/components/</code></td></tr><tr><td>Game logic (no React/Babylon)</td><td><code>src/game/</code></td></tr><tr><td>Seeded RNG (reproducible rolls)</td><td><code>src/game/util/rng.ts</code> — see <a href="./seeded-rng">Seeded RNG</a></td></tr><tr><td>Faction definitions/reputation</td><td><code>src/game/faction/</code> + <code>src/store/factionSlice.ts</code> — see <a href="./faction-system">Faction system</a></td></tr><tr><td>Commander orders / squad AI</td><td><code>src/game/ai/orders.ts</code> + <code>src/game/ai/soldierFSM.ts</code> — see <a href="./enemy-ai">Enemy AI</a></td></tr><tr><td>Character progression (XP/stats/skills)</td><td><code>src/game/progression/</code> + <code>src/store/progressionSlice.ts</code> — see <a href="./character-progression">Character progression</a></td></tr><tr><td>Asset streaming (GLB on demand)</td><td><code>src/game/streaming/</code></td></tr><tr><td>Persistent enemy corpses</td><td><code>src/game/corpses/</code> + <code>src/scenes/corpseManager.ts</code> — see <a href="./corpses">Corpses</a></td></tr><tr><td>Save/load (IndexedDB)</td><td><code>src/game/save/</code></td></tr><tr><td>User settings (rebind, quality)</td><td><code>src/game/settings/</code> — see <a href="./settings">Settings</a></td></tr><tr><td>Shared state</td><td><code>src/store/</code> (a new slice) — see <a href="./state-management">State management</a></td></tr><tr><td>A 3D model / texture / sound</td><td><code>assets/</code> (tracked by Git LFS)</td></tr><tr><td>Documentation</td><td><code>docs/</code> (same change as the code)</td></tr></tbody></table><h2 id="data-flow" tabindex="-1">Data flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data flow&quot;">​</a></h2><p><code>main.tsx</code> mounts React inside a Redux <code>&lt;Provider&gt;</code> and renders the full-page app shell (<code>src/app/App.tsx</code>): a <code>100vw × 100vh</code> stage holding the 3D canvas with a HUD overlay. UI reads state via the typed <code>useAppSelector</code> hook and dispatches via <code>useAppDispatch</code> (both from <code>src/store</code>).</p><p>The Babylon lifecycle lives in <code>src/engine/</code>: <code>createGameEngine(canvas)</code> owns the <code>Engine</code>/<code>Scene</code>, the render loop, the high-DPI resize handler, and <code>dispose()</code>. The React side stays thin — <code>src/scenes/GameCanvas.tsx</code> only mounts the engine against a ref&#39;d canvas and disposes it on unmount. Engine code can read/dispatch to the same store, so game systems and UI stay in sync through Redux.</p><h2 id="game-loop" tabindex="-1">Game loop <a class="header-anchor" href="#game-loop" aria-label="Permalink to &quot;Game loop&quot;">​</a></h2><p>Simulation runs on a fixed timestep decoupled from render FPS, in <code>src/game/loop/</code> (engine-agnostic — no Babylon/React). A Babylon scene drives it by calling <code>loop.advance(deltaSeconds)</code> each render frame. See <a href="./game-loop">Game loop</a> for the system-registration API and how to add a system.</p><h2 id="character-controller" tabindex="-1">Character controller <a class="header-anchor" href="#character-controller" aria-label="Permalink to &quot;Character controller&quot;">​</a></h2><p>The capsule character and its third-person follow camera live in <code>src/game/controller/</code> and <code>src/game/camera/</code>. Like the input system, each splits a pure, NullEngine-tested math core (gravity, ground clamp, jump, coyote-time, camera boom) from a thin Babylon binding that runs as a loop <code>System</code>. A self-contained dev scene is reachable at <code>?dev=controller</code>. See <a href="./character-controller">Character controller</a>.</p><h2 id="tree-impostors-distance-lod" tabindex="-1">Tree impostors (distance LOD) <a class="header-anchor" href="#tree-impostors-distance-lod" aria-label="Permalink to &quot;Tree impostors (distance LOD)&quot;">​</a></h2><p>The dense forest (Phase 5) cannot afford to draw every tree&#39;s full GLB (~1357 tris) hundreds of times. <code>src/game/streaming/treeImpostor.ts</code> collapses distant trees to a single camera-facing <strong>billboard impostor</strong> (2 tris) using Babylon&#39;s native per-mesh LOD (<code>mesh.addLODLevel</code>), so the engine swaps full mesh ↔ billboard by camera distance with no per-frame loop. A mesh used as an LOD level is &quot;linked&quot; and never drawn independently, so there is no double-draw, and instances inherit their source&#39;s LOD levels — keeping the layer compatible with the future thin-instanced forest (E5.3). A dense-forest benchmark scene is reachable at <code>?dev=impostor</code>. See <a href="./asset-streaming#tree-impostors-distance-lod">Asset streaming › Tree impostors</a>.</p><h2 id="performance-budget-60fps-on-mid-hardware" tabindex="-1">Performance budget (60fps on mid hardware) <a class="header-anchor" href="#performance-budget-60fps-on-mid-hardware" aria-label="Permalink to &quot;Performance budget (60fps on mid hardware)&quot;">​</a></h2><p>The dense-forest layers above exist to hold a frame inside a fixed budget. That budget lives as data in <code>src/game/perf/budget.ts</code> (60fps / 16.67ms; draw-call and active-index ceilings) with a pure evaluator, a scene <code>FrameProfiler</code> that grades a rolling mean, and a DOM <code>PerfHud</code> overlay. A live profiling bench over a 576-tree forest is reachable at <code>?dev=perf</code>. See <a href="./performance-budget">Performance budget</a> (E5.4).</p><h2 id="caravan-respawn-flo-456" tabindex="-1">Caravan respawn (FLO-456) <a class="header-anchor" href="#caravan-respawn-flo-456" aria-label="Permalink to &quot;Caravan respawn (FLO-456)&quot;">​</a></h2><p>Caravans are the primary gold faucet. Each zone registers one caravan per anchor in <code>src/game/world/</code> zone content. When a caravan is looted and defeated, its anchor records a <code>defeatedAt</code> timestamp. The <strong>pure scheduler</strong><code>src/game/ai/caravanRespawn.ts</code> (<code>getAnchorsToRearm</code>) is polled every frame in <code>forestScene.ts</code> and <code>humanLandsScene.ts</code>: once <code>CARAVAN_RESPAWN_MS</code> (60 s) has elapsed, the dead caravan mesh is disposed and a fresh <code>CaravanEnemy</code> is created at the same anchor. The anchor count never grows — there are never more live caravans than the zone&#39;s original anchor set. The scheduler is engine-agnostic and fully unit-tested (no Babylon import). See <a href="./../decisions/0005-win-goal-conquest">ADR 0005</a>.</p>`,18)])])}const u=a(o,[["render",r]]);export{m as __pageData,u as default};
